// Hava soyuq olarsa çay, isti olarsa şirə seçirik
let temperature = 15;
if (temperature < 20) {
  console.log("İsti çay iç!");
} else {
  console.log("Meyvə şirəsi iç!");
}
// nəticə: İsti çay iç!

// Çoxlu şərt nümunəsi
let temperature = 25;
if (temperature < 20) {
  console.log("İsti çay iç!");
} else if (temperature < 30) {
  console.log("Su iç!");
} else {
  console.log("Meyvə şirəsi iç!");
}
// nəticə: Su iç!

// Blok scope-u nümunəsi
if (true) {
  let message = "Şərt doğrudur!";
  console.log(message); // nəticə: Şərt doğrudur!
}
// console.log(message); // Xəta: message is not defined

// if və switch müqayisəsi
let day = "bazar ertəsi";
if (day === "bazar ertəsi") {
  console.log("İşə hazırlaş!");
} else {
  console.log("Rahatlan!");
}
// nəticə: İşə hazırlaş!

// Eyni tapşırıq switch ilə
switch (day) {
  case "bazar ertəsi":
    console.log("İşə hazırlaş!");
    break;
  default:
    console.log("Rahatlan!");
}
// nəticə: İşə hazırlaş!

