// Choose tea if cold, juice if warm
let temperature = 15;
if (temperature < 20) {
  console.log("Drink hot tea!");
} else {
  console.log("Drink fruit juice!");
}
// Output: Drink hot tea!

// Multiple conditions example
let temperature = 25;
if (temperature < 20) {
  console.log("Drink hot tea!");
} else if (temperature < 30) {
  console.log("Drink water!");
} else {
  console.log("Drink fruit juice!");
}
// Output: Drink water!

// Block scope example
if (true) {
  let message = "Condition is true!";
  console.log(message); // Output: Condition is true!
}
// console.log(message); // Error: message is not defined

// Comparing if and switch
let day = "Monday";
if (day === "Monday") {
  console.log("Get ready for work!");
} else {
  console.log("Relax!");
}
// Output: Get ready for work!

// Same task with switch
switch (day) {
  case "Monday":
    console.log("Get ready for work!");
    break;
  default:
    console.log("Relax!");
}
// Output: Get ready for work!

