// Выбираем чай, если холодно, сок, если тепло
let temperature = 15;
if (temperature < 20) {
  console.log("Пей горячий чай!");
} else {
  console.log("Пей фруктовый сок!");
}
// Вывод: Пей горячий чай!

// Пример с несколькими условиями
let temperature = 25;
if (temperature < 20) {
  console.log("Пей горячий чай!");
} else if (temperature < 30) {
  console.log("Пей воду!");
} else {
  console.log("Пей фруктовый сок!");
}
// Вывод: Пей воду!

// Пример с блочной областью видимости
if (true) {
  let message = "Условие истинно!";
  console.log(message); // Вывод: Условие истинно!
}
// console.log(message); // Ошибка: message is not defined

// Сравнение if и switch
let day = "понедельник";
if (day === "понедельник") {
  console.log("Готовься к работе!");
} else {
  console.log("Отдыхай!");
}
// Вывод: Готовься к работе!

// То же с switch
switch (day) {
  case "понедельник":
    console.log("Готовься к работе!");
    break;
  default:
    console.log("Отдыхай!");
}
// Вывод: Готовься к работе!

